package com.enterprise.samlsp.service;

import com.enterprise.samlsp.model.SamlAssertion;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.w3c.dom.*;
import org.xml.sax.InputSource;

import javax.xml.XMLConstants;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import java.io.StringReader;
import java.time.Instant;
import java.util.HashMap;
import java.util.Map;

@Service
public class SamlXmlParser {

    private static final Logger logger = LoggerFactory.getLogger(SamlXmlParser.class);

    private static final String SAML2_PROTOCOL_NS = "urn:oasis:names:tc:SAML:2.0:protocol";
    private static final String SAML2_ASSERTION_NS = "urn:oasis:names:tc:SAML:2.0:assertion";

    public SamlAssertion parseSamlResponse(String samlResponseXml) throws Exception {
        Document document = parseXmlDocument(samlResponseXml);
        SamlAssertion assertion = new SamlAssertion();

        // Parse Response element
        Element responseElement = document.getDocumentElement();
        assertion.setDestination(responseElement.getAttribute("Destination"));
        assertion.setInResponseTo(responseElement.getAttribute("InResponseTo"));

        // Parse Status
        NodeList statusCodeNodes = responseElement.getElementsByTagNameNS(SAML2_PROTOCOL_NS, "StatusCode");
        if (statusCodeNodes.getLength() > 0) {
            Element statusCodeElement = (Element) statusCodeNodes.item(0);
            assertion.setStatusCode(statusCodeElement.getAttribute("Value"));
        }

        // Parse Issuer at response level
        NodeList issuerNodes = responseElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Issuer");
        if (issuerNodes.getLength() > 0) {
            assertion.setIssuer(issuerNodes.item(0).getTextContent().trim());
        }

        // Parse Assertion
        NodeList assertionNodes = responseElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Assertion");
        if (assertionNodes.getLength() == 0) {
            throw new SamlProcessingException("No Assertion found in SAML Response");
        }

        Element assertionElement = (Element) assertionNodes.item(0);
        assertion.setId(assertionElement.getAttribute("ID"));

        String issueInstantStr = assertionElement.getAttribute("IssueInstant");
        if (issueInstantStr != null && !issueInstantStr.isEmpty()) {
            assertion.setIssueInstant(Instant.parse(issueInstantStr));
        }

        // Parse Assertion Issuer
        NodeList assertionIssuerNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Issuer");
        if (assertionIssuerNodes.getLength() > 0) {
            assertion.setIssuer(assertionIssuerNodes.item(0).getTextContent().trim());
        }

        // Parse Subject
        parseSubject(assertionElement, assertion);

        // Parse Conditions
        parseConditions(assertionElement, assertion);

        // Parse AuthnStatement
        parseAuthnStatement(assertionElement, assertion);

        // Parse AttributeStatement
        parseAttributeStatement(assertionElement, assertion);

        logger.info("Successfully parsed SAML assertion for NameID: {}", assertion.getNameId());
        return assertion;
    }

    private Document parseXmlDocument(String xml) throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);

        // Security: Prevent XXE attacks
        factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
        factory.setXIncludeAware(false);
        factory.setExpandEntityReferences(false);

        DocumentBuilder builder = factory.newDocumentBuilder();
        InputSource inputSource = new InputSource(new StringReader(xml));
        return builder.parse(inputSource);
    }

    private void parseSubject(Element assertionElement, SamlAssertion assertion) {
        NodeList subjectNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Subject");
        if (subjectNodes.getLength() > 0) {
            Element subjectElement = (Element) subjectNodes.item(0);

            // NameID
            NodeList nameIdNodes = subjectElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "NameID");
            if (nameIdNodes.getLength() > 0) {
                Element nameIdElement = (Element) nameIdNodes.item(0);
                assertion.setNameId(nameIdElement.getTextContent().trim());
                assertion.setNameIdFormat(nameIdElement.getAttribute("Format"));
            }

            // SubjectConfirmation
            NodeList subjectConfirmationDataNodes = subjectElement.getElementsByTagNameNS(
                    SAML2_ASSERTION_NS, "SubjectConfirmationData");
            if (subjectConfirmationDataNodes.getLength() > 0) {
                Element scdElement = (Element) subjectConfirmationDataNodes.item(0);
                assertion.setSubjectConfirmationRecipient(scdElement.getAttribute("Recipient"));
                String notOnOrAfter = scdElement.getAttribute("NotOnOrAfter");
                if (notOnOrAfter != null && !notOnOrAfter.isEmpty()) {
                    assertion.setSubjectConfirmationNotOnOrAfter(Instant.parse(notOnOrAfter));
                }
                String inResponseTo = scdElement.getAttribute("InResponseTo");
                if (inResponseTo != null && !inResponseTo.isEmpty()) {
                    assertion.setInResponseTo(inResponseTo);
                }
            }
        }
    }

    private void parseConditions(Element assertionElement, SamlAssertion assertion) {
        NodeList conditionsNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Conditions");
        if (conditionsNodes.getLength() > 0) {
            Element conditionsElement = (Element) conditionsNodes.item(0);

            String notBefore = conditionsElement.getAttribute("NotBefore");
            if (notBefore != null && !notBefore.isEmpty()) {
                assertion.setConditionsNotBefore(Instant.parse(notBefore));
            }

            String notOnOrAfter = conditionsElement.getAttribute("NotOnOrAfter");
            if (notOnOrAfter != null && !notOnOrAfter.isEmpty()) {
                assertion.setConditionsNotOnOrAfter(Instant.parse(notOnOrAfter));
            }

            // AudienceRestriction
            NodeList audienceNodes = conditionsElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Audience");
            if (audienceNodes.getLength() > 0) {
                assertion.setAudience(audienceNodes.item(0).getTextContent().trim());
            }
        }
    }

    private void parseAuthnStatement(Element assertionElement, SamlAssertion assertion) {
        NodeList authnStatementNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AuthnStatement");
        if (authnStatementNodes.getLength() > 0) {
            Element authnStatementElement = (Element) authnStatementNodes.item(0);

            String authnInstant = authnStatementElement.getAttribute("AuthnInstant");
            if (authnInstant != null && !authnInstant.isEmpty()) {
                assertion.setAuthnInstant(Instant.parse(authnInstant));
            }

            assertion.setSessionIndex(authnStatementElement.getAttribute("SessionIndex"));

            // AuthnContext
            NodeList authnContextClassRefNodes = authnStatementElement.getElementsByTagNameNS(
                    SAML2_ASSERTION_NS, "AuthnContextClassRef");
            if (authnContextClassRefNodes.getLength() > 0) {
                assertion.setAuthnContextClassRef(authnContextClassRefNodes.item(0).getTextContent().trim());
            }
        }
    }

    private void parseAttributeStatement(Element assertionElement, SamlAssertion assertion) {
        Map<String, String> attributes = new HashMap<>();

        NodeList attributeStatementNodes = assertionElement.getElementsByTagNameNS(
                SAML2_ASSERTION_NS, "AttributeStatement");
        if (attributeStatementNodes.getLength() > 0) {
            Element attributeStatementElement = (Element) attributeStatementNodes.item(0);

            NodeList attributeNodes = attributeStatementElement.getElementsByTagNameNS(
                    SAML2_ASSERTION_NS, "Attribute");
            for (int i = 0; i < attributeNodes.getLength(); i++) {
                Element attributeElement = (Element) attributeNodes.item(i);
                String attributeName = attributeElement.getAttribute("Name");

                NodeList attributeValueNodes = attributeElement.getElementsByTagNameNS(
                        SAML2_ASSERTION_NS, "AttributeValue");
                if (attributeValueNodes.getLength() > 0) {
                    String attributeValue = attributeValueNodes.item(0).getTextContent().trim();
                    attributes.put(attributeName, attributeValue);
                    logger.debug("Parsed SAML attribute: {} = {}", attributeName, attributeValue);
                }
            }
        }

        assertion.setAttributes(attributes);
    }
}

