package com.enterprise.samlsp.service;

import com.enterprise.samlsp.config.SamlSpProperties;
import com.enterprise.samlsp.model.SamlAssertion;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import java.time.Duration;
import java.time.Instant;

@Service
public class SamlAssertionValidator {

    private static final Logger logger = LoggerFactory.getLogger(SamlAssertionValidator.class);
    private static final String STATUS_SUCCESS = "urn:oasis:names:tc:SAML:2.0:status:Success";

    private final SamlSpProperties samlSpProperties;

    public SamlAssertionValidator(SamlSpProperties samlSpProperties) {
        this.samlSpProperties = samlSpProperties;
    }

    public void validate(SamlAssertion assertion) {
        validateStatus(assertion);
        validateIssuer(assertion);
        validateDestination(assertion);
        validateConditions(assertion);
        validateSubjectConfirmation(assertion);
        validateAuthnStatement(assertion);
        validateNameId(assertion);

        logger.info("SAML assertion validation passed for NameID: {}", assertion.getNameId());
    }

    private void validateStatus(SamlAssertion assertion) {
        if (assertion.getStatusCode() == null || !assertion.getStatusCode().equals(STATUS_SUCCESS)) {
            throw new SamlProcessingException(
                    "SAML Response status is not Success: " + assertion.getStatusCode());
        }
    }

    private void validateIssuer(SamlAssertion assertion) {
        if (assertion.getIssuer() == null || assertion.getIssuer().isEmpty()) {
            throw new SamlProcessingException("SAML Assertion Issuer is missing");
        }
        if (!assertion.getIssuer().equals(samlSpProperties.getIdpEntityId())) {
            throw new SamlProcessingException(
                    "SAML Assertion Issuer mismatch. Expected: " + samlSpProperties.getIdpEntityId() +
                            ", Got: " + assertion.getIssuer());
        }
    }

    private void validateDestination(SamlAssertion assertion) {
        if (assertion.getDestination() != null && !assertion.getDestination().isEmpty()) {
            if (!assertion.getDestination().equals(samlSpProperties.getAcsUrl())) {
                throw new SamlProcessingException(
                        "SAML Response Destination mismatch. Expected: " + samlSpProperties.getAcsUrl() +
                                ", Got: " + assertion.getDestination());
            }
        }
    }

    private void validateConditions(SamlAssertion assertion) {
        Instant now = Instant.now();
        Duration clockSkew = Duration.ofSeconds(samlSpProperties.getClockSkewSeconds());

        if (assertion.getConditionsNotBefore() != null) {
            Instant adjustedNotBefore = assertion.getConditionsNotBefore().minus(clockSkew);
            if (now.isBefore(adjustedNotBefore)) {
                throw new SamlProcessingException(
                        "SAML Assertion is not yet valid. NotBefore: " + assertion.getConditionsNotBefore());
            }
        }

        if (assertion.getConditionsNotOnOrAfter() != null) {
            Instant adjustedNotOnOrAfter = assertion.getConditionsNotOnOrAfter().plus(clockSkew);
            if (now.isAfter(adjustedNotOnOrAfter)) {
                throw new SamlProcessingException(
                        "SAML Assertion has expired. NotOnOrAfter: " + assertion.getConditionsNotOnOrAfter());
            }
        }

        // Validate audience
        if (assertion.getAudience() != null && !assertion.getAudience().isEmpty()) {
            if (!assertion.getAudience().equals(samlSpProperties.getEntityId())) {
                throw new SamlProcessingException(
                        "SAML Assertion Audience mismatch. Expected: " + samlSpProperties.getEntityId() +
                                ", Got: " + assertion.getAudience());
            }
        }
    }

    private void validateSubjectConfirmation(SamlAssertion assertion) {
        if (assertion.getSubjectConfirmationRecipient() != null &&
                !assertion.getSubjectConfirmationRecipient().isEmpty()) {
            if (!assertion.getSubjectConfirmationRecipient().equals(samlSpProperties.getAcsUrl())) {
                throw new SamlProcessingException(
                        "SubjectConfirmation Recipient mismatch. Expected: " + samlSpProperties.getAcsUrl() +
                                ", Got: " + assertion.getSubjectConfirmationRecipient());
            }
        }

        if (assertion.getSubjectConfirmationNotOnOrAfter() != null) {
            Instant now = Instant.now();
            Duration clockSkew = Duration.ofSeconds(samlSpProperties.getClockSkewSeconds());
            Instant adjustedNotOnOrAfter = assertion.getSubjectConfirmationNotOnOrAfter().plus(clockSkew);
            if (now.isAfter(adjustedNotOnOrAfter)) {
                throw new SamlProcessingException(
                        "SubjectConfirmation has expired. NotOnOrAfter: " +
                                assertion.getSubjectConfirmationNotOnOrAfter());
            }
        }
    }

    private void validateAuthnStatement(SamlAssertion assertion) {
        if (assertion.getAuthnInstant() != null) {
            Instant now = Instant.now();
            Duration maxAge = Duration.ofSeconds(samlSpProperties.getMaxAuthenticationAgeSeconds());
            if (now.isAfter(assertion.getAuthnInstant().plus(maxAge))) {
                throw new SamlProcessingException(
                        "Authentication is too old. AuthnInstant: " + assertion.getAuthnInstant());
            }
        }
    }

    private void validateNameId(SamlAssertion assertion) {
        if (assertion.getNameId() == null || assertion.getNameId().trim().isEmpty()) {
            throw new SamlProcessingException("SAML Assertion NameID is missing or empty");
        }
    }
}

