package com.enterprise.samlsp.service;

import com.enterprise.samlsp.model.SamlAssertion;
import com.enterprise.samlsp.model.SamlUserAttributes;
import com.enterprise.samlsp.security.SamlAuthenticationToken;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Service;

import jakarta.servlet.http.HttpSession;
import java.util.ArrayList;
import java.util.Base64;
import java.util.List;

@Service
public class SamlAuthenticationService {

    private static final Logger logger = LoggerFactory.getLogger(SamlAuthenticationService.class);
    public static final String SAML_USER_ATTRIBUTES_KEY = "SAML_USER_ATTRIBUTES";

    private final SamlXmlParser samlXmlParser;
    private final SamlAssertionValidator assertionValidator;

    public SamlAuthenticationService(SamlXmlParser samlXmlParser,
                                      SamlAssertionValidator assertionValidator) {
        this.samlXmlParser = samlXmlParser;
        this.assertionValidator = assertionValidator;
    }

    public SamlUserAttributes processSamlResponse(String encodedSamlResponse, HttpSession session) {
        try {
            // Decode Base64 SAML Response
            String samlResponseXml = new String(Base64.getDecoder().decode(encodedSamlResponse));
            logger.debug("Decoded SAML Response XML");

            // Parse the SAML Response
            SamlAssertion assertion = samlXmlParser.parseSamlResponse(samlResponseXml);

            // Validate the assertion
            assertionValidator.validate(assertion);

            // Extract user attributes
            SamlUserAttributes userAttributes = extractUserAttributes(assertion);

            // Store in session
            session.setAttribute(SAML_USER_ATTRIBUTES_KEY, userAttributes);

            // Create Spring Security authentication
            createSecurityContext(userAttributes);

            logger.info("SAML authentication successful for user: {}", userAttributes.getNameId());
            return userAttributes;

        } catch (SamlProcessingException e) {
            logger.error("SAML processing error: {}", e.getMessage());
            throw e;
        } catch (Exception e) {
            logger.error("Error processing SAML response", e);
            throw new SamlProcessingException("Failed to process SAML response: " + e.getMessage(), e);
        }
    }

    private SamlUserAttributes extractUserAttributes(SamlAssertion assertion) {
        SamlUserAttributes userAttributes = new SamlUserAttributes();
        userAttributes.setNameId(assertion.getNameId());
        userAttributes.setSessionIndex(assertion.getSessionIndex());
        userAttributes.setIssuer(assertion.getIssuer());
        userAttributes.setAuthenticationInstant(assertion.getAuthnInstant());
        userAttributes.setSessionNotOnOrAfter(assertion.getConditionsNotOnOrAfter());

        if (assertion.getAttributes() != null) {
            userAttributes.setAttributes(assertion.getAttributes());
        }

        // Map common SAML attributes to friendly names
        mapCommonAttributes(userAttributes);

        return userAttributes;
    }

    private void mapCommonAttributes(SamlUserAttributes userAttributes) {
        // Map common SAML attribute URNs to friendly names
        mapAttribute(userAttributes,
                "urn:oid:0.9.2342.19200300.100.1.3", "email");
        mapAttribute(userAttributes,
                "urn:oid:2.5.4.42", "firstName");
        mapAttribute(userAttributes,
                "urn:oid:2.5.4.4", "lastName");
        mapAttribute(userAttributes,
                "urn:oid:2.16.840.1.113730.3.1.241", "displayName");
        mapAttribute(userAttributes,
                "urn:oid:1.3.6.1.4.1.5923.1.1.1.7", "eduPersonEntitlement");
        mapAttribute(userAttributes,
                "urn:oid:1.3.6.1.4.1.5923.1.1.1.1", "eduPersonAffiliation");

        // Also handle common friendly name attributes
        mapAttribute(userAttributes, "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/emailaddress", "email");
        mapAttribute(userAttributes, "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/givenname", "firstName");
        mapAttribute(userAttributes, "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/surname", "lastName");
        mapAttribute(userAttributes, "http://schemas.microsoft.com/ws/2008/06/identity/claims/role", "role");
        mapAttribute(userAttributes, "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/name", "displayName");
    }

    private void mapAttribute(SamlUserAttributes userAttributes, String urn, String friendlyName) {
        String value = userAttributes.getAttribute(urn);
        if (value != null && !userAttributes.getAttributes().containsKey(friendlyName)) {
            userAttributes.addAttribute(friendlyName, value);
        }
    }

    private void createSecurityContext(SamlUserAttributes userAttributes) {
        List<SimpleGrantedAuthority> authorities = new ArrayList<>();
        authorities.add(new SimpleGrantedAuthority("ROLE_USER"));

        // Add role from SAML attributes if present
        String role = userAttributes.getAttribute("role");
        if (role != null && !role.isEmpty()) {
            String[] roles = role.split(",");
            for (String r : roles) {
                String trimmedRole = r.trim();
                if (!trimmedRole.startsWith("ROLE_")) {
                    trimmedRole = "ROLE_" + trimmedRole.toUpperCase();
                }
                authorities.add(new SimpleGrantedAuthority(trimmedRole));
            }
        }

        SamlAuthenticationToken authentication = new SamlAuthenticationToken(
                userAttributes.getNameId(), userAttributes, authorities);

        SecurityContextHolder.getContext().setAuthentication(authentication);
    }
}

// --- SAML Request Generator ---

package com.enterprise.samlsp.service;

import com.enterprise.samlsp.config.SamlSpProperties;
import org.springframework.stereotype.Service;

import java.io.ByteArrayOutputStream;
import java.nio.charset.StandardCharsets;
import java.time.Instant;
import java.util.Base64;
import java.util.UUID;
import java.util.zip.Deflater;
import java.util.zip.DeflaterOutputStream;

@Service
public class SamlRequestGenerator {

    private final SamlSpProperties samlSpProperties;

    public SamlRequestGenerator(SamlSpProperties samlSpProperties) {
        this.samlSpProperties = samlSpProperties;
    }

    public String generateAuthnRequest() throws Exception {
        String requestId = "_" + UUID.randomUUID().toString();
        String issueInstant = Instant.now().toString();

        String authnRequest = String.format(
                "<?xml version=\"1.0\" encoding=\"UTF-8\"?>" +
                        "<samlp:AuthnRequest xmlns:samlp=\"urn:oasis:names:tc:SAML:2.0:protocol\" " +
                        "xmlns:saml=\"urn:oasis:names:tc:SAML:2.0:assertion\" " +
                        "ID=\"%s\" " +
                        "Version=\"2.0\" " +
                        "IssueInstant=\"%s\" " +
                        "Destination=\"%s\" " +
                        "AssertionConsumerServiceURL=\"%s\" " +
                        "ProtocolBinding=\"urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST\">" +
                        "<saml:Issuer>%s</saml:Issuer>" +
                        "<samlp:NameIDPolicy Format=\"urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress\" " +
                        "AllowCreate=\"true\"/>" +
                        "</samlp:AuthnRequest>",
                requestId, issueInstant, samlSpProperties.getIdpSsoUrl(),
                samlSpProperties.getAcsUrl(), samlSpProperties.getEntityId()
        );

        return encodeAuthnRequest(authnRequest);
    }

    private String encodeAuthnRequest(String authnRequest) throws Exception {
        ByteArrayOutputStream byteArrayOutputStream = new ByteArrayOutputStream();
        Deflater deflater = new Deflater(Deflater.DEFLATED, true);
        DeflaterOutputStream deflaterOutputStream = new DeflaterOutputStream(byteArrayOutputStream, deflater);
        deflaterOutputStream.write(authnRequest.getBytes(StandardCharsets.UTF_8));
        deflaterOutputStream.close();

        return Base64.getEncoder().encodeToString(byteArrayOutputStream.toByteArray());
    }

    public String getIdpSsoUrl() {
        return samlSpProperties.getIdpSsoUrl();
    }
}

// --- SAML Session Manager ---

package com.enterprise.samlsp.service;

import com.enterprise.samlsp.model.SamlUserAttributes;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import jakarta.servlet.http.HttpSession;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

@Service
public class SamlSessionManager {

    private static final Logger logger = LoggerFactory.getLogger(SamlSessionManager.class);

    // Track sessions by session index for single logout support
    private final Map<String, String> sessionIndexToSessionId = new ConcurrentHashMap<>();
    private final Map<String, HttpSession> activeSessions = new ConcurrentHashMap<>();

    public void registerSession(HttpSession session, SamlUserAttributes userAttributes) {
        String sessionId = session.getId();
        String sessionIndex = userAttributes.getSessionIndex();

        activeSessions.put(sessionId, session);
        if (sessionIndex != null) {
            sessionIndexToSessionId.put(sessionIndex, sessionId);
        }

        logger.info("Registered SAML session for user: {}, sessionId: {}", 
                userAttributes.getNameId(), sessionId);
    }

    public void invalidateSession(HttpSession session) {
        String sessionId = session.getId();
        SamlUserAttributes userAttributes = (SamlUserAttributes) session.getAttribute(
                SamlAuthenticationService.SAML_USER_ATTRIBUTES_KEY);

        if (userAttributes != null && userAttributes.getSessionIndex() != null) {
            sessionIndexToSessionId.remove(userAttributes.getSessionIndex());
        }
        activeSessions.remove(sessionId);

        try {
            session.invalidate();
        } catch (IllegalStateException e) {
            logger.debug("Session already invalidated: {}", sessionId);
        }

        logger.info("Invalidated SAML session: {}", sessionId);
    }

    public void invalidateBySessionIndex(String sessionIndex) {
        String sessionId = sessionIndexToSessionId.get(sessionIndex);
        if (sessionId != null) {
            HttpSession session = activeSessions.get(sessionId);
            if (session != null) {
                invalidateSession(session);
            }
        }
    }

    public SamlUserAttributes getUserAttributes(HttpSession session) {
        return (SamlUserAttributes) session.getAttribute(SamlAuthenticationService.SAML_USER_ATTRIBUTES_KEY);
    }

    public boolean isSessionValid(HttpSession session) {
        SamlUserAttributes userAttributes = getUserAttributes(session);
        if (userAttributes == null) {
            return false;
        }

        if (userAttributes.getSessionNotOnOrAfter() != null) {
            return java.time.Instant.now().isBefore(userAttributes.getSessionNotOnOrAfter());
        }

        return true;
    }
}

// --- SAML ACS Controller ---

package com.enterprise.samlsp.controller;

import com.enterprise.samlsp.model.SamlUserAttributes;
import com.enterprise.samlsp.service.SamlAuthenticationService;
import com.enterprise.samlsp.service.SamlProcessingException;
import com.enterprise.samlsp.service.SamlSessionManager;
import com.enterprise.samlsp.config.SamlSpProperties;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.servlet.mvc.support.RedirectAttributes;

import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpSession;

@Controller
public class SamlAcsController {

    private static final Logger logger = LoggerFactory.getLogger(SamlAcsController.class);

    private final SamlAuthenticationService authenticationService;
    private final SamlSessionManager sessionManager;
    private final SamlSpProperties samlSpProperties;

    public SamlAcsController(SamlAuthenticationService authenticationService,
                              SamlSessionManager sessionManager,
                              SamlSpProperties samlSpProperties) {
        this.authenticationService = authenticationService;
        this.sessionManager = sessionManager;
        this.samlSpProperties = samlSpProperties;
    }

    @PostMapping("/saml/acs")
    public String assertionConsumerService(
            @RequestParam("SAMLResponse") String samlResponse,
            @RequestParam(value = "RelayState", required = false) String relayState,
            HttpServletRequest request,
            RedirectAttributes redirectAttributes) {

        logger.info("Received SAML Response at ACS endpoint");

        try {
            HttpSession session = request.getSession(true);

            SamlUserAttributes userAttributes = authenticationService.processSamlResponse(
                    samlResponse, session);

            sessionManager.registerSession(session, userAttributes);

            logger.info("SAML SSO completed successfully for user: {}", userAttributes.getNameId());

            // Redirect to RelayState URL or default success URL
            String redirectUrl = (relayState != null && !relayState.isEmpty())
                    ? relayState
                    : samlSpProperties.getDefaultSuccessUrl();

            return "redirect:" + redirectUrl;

        } catch (SamlProcessingException e) {
            logger.error("SAML authentication failed: {}", e.getMessage());
            redirectAttributes.addFlashAttribute("error", "SAML authentication failed: " + e.getMessage());
            return "redirect:/login?error=saml_auth_failed";
        } catch (Exception e) {
            logger.error("Unexpected error during SAML authentication", e);
            redirectAttributes.addFlashAttribute("error", "An unexpected error occurred during authentication");
            return "redirect:/login?error=unexpected";
        }
    }
}

// --- SAML Login Controller ---

package com.enterprise.samlsp.controller;

import com.enterprise.samlsp.service.SamlRequestGenerator;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;

import java.net.URLEncoder;
import java.nio.charset.StandardCharsets;

@Controller
public class SamlLoginController {

    private static final Logger logger = LoggerFactory.getLogger(SamlLoginController.class);

    private final SamlRequestGenerator requestGenerator;

    public SamlLoginController(SamlRequestGenerator requestGenerator) {
        this.requestGenerator = requestGenerator;
    }

    @GetMapping("/login")
    public String loginPage(Model model) {
        return "login";
    }

    @GetMapping("/saml/login")
    public String initiateSamlLogin() {
        try {
            String encodedRequest = requestGenerator.generateAuthnRequest();
            String idpUrl = requestGenerator.getIdpSsoUrl();
            String redirectUrl = idpUrl + "?SAMLRequest=" +
                    URLEncoder.encode(encodedRequest, StandardCharsets.UTF_8);

            logger.info("Initiating SAML SSO, redirecting to IdP: {}", idpUrl);
            return "redirect:" + redirectUrl;

        } catch (Exception e) {
            logger.error("Error generating SAML AuthnRequest", e);
            return "redirect:/login?error=saml_request_failed";
        }
    }
}

