package com.enterprise.samlsp.controller;

import com.enterprise.samlsp.service.SamlSessionManager;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PostMapping;

import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpSession;

@Controller
public class SamlLogoutController {

    private static final Logger logger = LoggerFactory.getLogger(SamlLogoutController.class);

    private final SamlSessionManager sessionManager;

    public SamlLogoutController(SamlSessionManager sessionManager) {
        this.sessionManager = sessionManager;
    }

    @GetMapping("/saml/logout")
    public String logout(HttpServletRequest request) {
        return performLogout(request);
    }

    @PostMapping("/saml/logout")
    public String logoutPost(HttpServletRequest request) {
        return performLogout(request);
    }

    private String performLogout(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        if (session != null) {
            sessionManager.invalidateSession(session);
        }
        SecurityContextHolder.clearContext();

        logger.info("User logged out successfully");
        return "redirect:/login?logout=true";
    }
}

