package com.enterprise.samlsp.controller;

import com.enterprise.samlsp.model.SamlUserAttributes;
import com.enterprise.samlsp.service.SamlSessionManager;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;

import jakarta.servlet.http.HttpSession;

@Controller
public class DashboardController {

    private final SamlSessionManager sessionManager;

    public DashboardController(SamlSessionManager sessionManager) {
        this.sessionManager = sessionManager;
    }

    @GetMapping("/dashboard")
    public String dashboard(HttpSession session, Model model) {
        SamlUserAttributes userAttributes = sessionManager.getUserAttributes(session);
        if (userAttributes != null) {
            model.addAttribute("user", userAttributes);
            model.addAttribute("nameId", userAttributes.getNameId());
            model.addAttribute("attributes", userAttributes.getAttributes());
            model.addAttribute("issuer", userAttributes.getIssuer());
            model.addAttribute("authInstant", userAttributes.getAuthenticationInstant());
        }
        return "dashboard";
    }

    @GetMapping("/")
    public String home() {
        return "redirect:/dashboard";
    }
}

