// --- SAML Session Filter ---

package com.enterprise.samlsp.security;

import com.enterprise.samlsp.service.SamlSessionManager;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.web.filter.OncePerRequestFilter;

import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import java.io.IOException;

public class SamlSessionValidationFilter extends OncePerRequestFilter {

    private static final Logger logger = LoggerFactory.getLogger(SamlSessionValidationFilter.class);

    private final SamlSessionManager sessionManager;

    public SamlSessionValidationFilter(SamlSessionManager sessionManager) {
        this.sessionManager = sessionManager;
    }

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response,
                                     FilterChain filterChain) throws ServletException, IOException {

        HttpSession session = request.getSession(false);

        if (session != null && SecurityContextHolder.getContext().getAuthentication() != null) {
            if (!sessionManager.isSessionValid(session)) {
                logger.info("SAML session has expired, invalidating session");
                sessionManager.invalidateSession(session);
                SecurityContextHolder.clearContext();
                response.sendRedirect("/login?error=session_expired");
                return;
            }
        }

        filterChain.doFilter(request, response);
    }

    @Override
    protected boolean shouldNotFilter(HttpServletRequest request) {
        String path = request.getRequestURI();
        return path.startsWith("/saml/") || path.equals("/login") ||
                path.startsWith("/css/") || path.startsWith("/js/") ||
                path.startsWith("/images/") || path.equals("/error");
    }
}

// --- Security Configuration ---

package com.enterprise.samlsp.config;

import com.enterprise.samlsp.security.SamlSessionValidationFilter;
import com.enterprise.samlsp.service.SamlSessionManager;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;

@Configuration
@EnableWebSecurity
public class SecurityConfig {

    private final SamlSessionManager sessionManager;

    public SecurityConfig(SamlSessionManager sessionManager) {
        this.sessionManager = sessionManager;
    }

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
                .csrf(csrf -> csrf
                        .ignoringRequestMatchers("/saml/acs", "/saml/logout")
                )
                .authorizeHttpRequests(auth -> auth
                        .requestMatchers("/login", "/saml/acs", "/saml/login", "/saml/metadata",
                                "/saml/logout", "/error", "/css/**", "/js/**", "/images/**").permitAll()
                        .anyRequest().authenticated()
                )
                .formLogin(form -> form
                        .loginPage("/login")
                        .permitAll()
                )
                .logout(logout -> logout
                        .logoutUrl("/logout")
                        .logoutSuccessUrl("/login?logout=true")
                        .invalidateHttpSession(true)
                        .clearAuthentication(true)
                )
                .addFilterBefore(new SamlSessionValidationFilter(sessionManager),
                        UsernamePasswordAuthenticationFilter.class);

        return http.build();
    }
}

