package com.enterprise.samlsp.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.session.MapSessionRepository;
import org.springframework.session.config.annotation.web.http.EnableSpringHttpSession;

import java.util.concurrent.ConcurrentHashMap;

@Configuration
@EnableSpringHttpSession
public class SessionConfig {

    @Bean
    public MapSessionRepository sessionRepository() {
        MapSessionRepository repository = new MapSessionRepository(new ConcurrentHashMap<>());
        repository.setDefaultMaxInactiveInterval(3600);
        return repository;
    }
}

// --- REST API for user info ---

package com.enterprise.samlsp.controller;

import com.enterprise.samlsp.model.SamlUserAttributes;
import com.enterprise.samlsp.service.SamlSessionManager;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import jakarta.servlet.http.HttpSession;
import java.util.HashMap;
import java.util.Map;

@RestController
@RequestMapping("/api")
public class UserApiController {

    private final SamlSessionManager sessionManager;

    public UserApiController(SamlSessionManager sessionManager) {
        this.sessionManager = sessionManager;
    }

    @GetMapping("/user")
    public ResponseEntity<Map<String, Object>> getCurrentUser(HttpSession session) {
        SamlUserAttributes userAttributes = sessionManager.getUserAttributes(session);

        if (userAttributes == null) {
            return ResponseEntity.status(401).build();
        }

        Map<String, Object> userInfo = new HashMap<>();
        userInfo.put("nameId", userAttributes.getNameId());
        userInfo.put("issuer", userAttributes.getIssuer());
        userInfo.put("sessionIndex", userAttributes.getSessionIndex());
        userInfo.put("authenticationInstant", userAttributes.getAuthenticationInstant());
        userInfo.put("attributes", userAttributes.getAttributes());

        return ResponseEntity.ok(userInfo);
    }

    @GetMapping("/user/attributes")
    public ResponseEntity<Map<String, String>> getUserAttributes(HttpSession session) {
        SamlUserAttributes userAttributes = sessionManager.getUserAttributes(session);

        if (userAttributes == null) {
            return ResponseEntity.status(401).build();
        }

        return ResponseEntity.ok(userAttributes.getAttributes());
    }
}

// --- Global Exception Handler ---

package com.enterprise.samlsp.controller;

import com.enterprise.samlsp.service.SamlProcessingException;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.HttpStatus;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.ControllerAdvice;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.ResponseStatus;

@ControllerAdvice
public class GlobalExceptionHandler {

    private static final Logger logger = LoggerFactory.getLogger(GlobalExceptionHandler.class);

    @ExceptionHandler(SamlProcessingException.class)
    @ResponseStatus(HttpStatus.UNAUTHORIZED)
    public String handleSamlProcessingException(SamlProcessingException ex, Model model) {
        logger.error("SAML processing error: {}", ex.getMessage());
        model.addAttribute("error", "Authentication failed: " + ex.getMessage());
        return "error";
    }

    @ExceptionHandler(Exception.class)
    @ResponseStatus(HttpStatus.INTERNAL_SERVER_ERROR)
    public String handleGeneralException(Exception ex, Model model) {
        logger.error("Unexpected error", ex);
        model.addAttribute("error", "An unexpected error occurred");
        return "error";
    }
}